import React from 'react';
import ReactDOM from 'react-dom/client';
import { BrowserRouter } from 'react-router-dom';
import App from './App';
import { AuthProvider } from './providers/AuthProvider';
import { SafetyProvider } from './providers/SafetyProvider';
import { SchedulingProvider } from './providers/SchedulingProvider';
import { SubscriptionProvider } from './contexts/SubscriptionContext'; // Make sure path is correct

console.log('Starting app initialization');

try {
  const root = ReactDOM.createRoot(document.getElementById('root'));
  console.log('Root created');

  root.render(
    <React.StrictMode>
      <BrowserRouter>
        <AuthProvider>
          <SubscriptionProvider>  {/* Added here */}
            <SchedulingProvider>
              <SafetyProvider>
                <App />
              </SafetyProvider>
            </SchedulingProvider>
          </SubscriptionProvider>
        </AuthProvider>
      </BrowserRouter>
    </React.StrictMode>
  );
  console.log('Render completed');
} catch (error) {
  console.error('Error during initialization:', error);
}
